INSERT INTO "Appointment" ("id", "type", "patientId", "guestName", "guestPhone", "guestEmail", "date", "timeSlot", "status", "notes", "meetingId", "meetingUrl", "createdAt", "updatedAt", "cancellationReason") VALUES ('cmoxjpbsp000lvfjk2va1vd0u', 'IN_CLINIC', NULL, NULL, NULL, NULL, '2026-05-09T00:00:00.000Z', '09:00', 'pending', '2001', NULL, NULL, '2026-05-08T23:27:44.377Z', '2026-05-08T23:27:44.377Z', NULL);
INSERT INTO "BlogPost" ("id", "titleAr", "titleEn", "slugAr", "slugEn", "contentAr", "contentEn", "excerptAr", "excerptEn", "metaTitleAr", "metaTitleEn", "metaDescriptionAr", "metaDescriptionEn", "keywords", "categoryId", "status", "featuredImage", "createdAt", "updatedAt", "showOnHomepage") VALUES ('cmoxkx85s0008vfj0bkybaeq7', 'طريقك لصحة الكلى: فهم العلامات المبكرة وطرق الوقاية', 'The Path to Kidney Health: Understanding Early Signs and Prevention', 'طريقك-لصحة-الكلى-فهم-العلامات-المبكرة-وطرق-الوقاية', 'the-path-to-kidney-health-understanding-early-signs-and-prevention', '<h2><strong>لماذا تعتبر صحة الكلى أمراً حيوياً؟</strong></h2><p>تلعب الكلى دوراً حيوياً في الحفاظ على الصحة العامة من خلال تصفية الفضلات من الدم وتنظيم ضغط الدم. ومع ذلك، لا يدرك الكثير من الناس وجود مشاكل في الكلى حتى تصل إلى مراحل متقدمة.</p><h3><strong>علامات شائعة يجب مراقبتها</strong></h3><ul><li><p>تغيرات في عدد مرات التبول أو لون البول.</p></li><li><p>تورم في الكاحلين أو القدمين أو الساقين.</p></li><li><p>التعب المستمر والضعف العام.</p></li><li><p>ضيق التنفس دون سبب واضح.</p></li></ul><p>الكشف المبكر من خلال الفحوصات الدورية هو أفضل وسيلة للوقاية من أمراض الكلى المزمنة. استشر الدكتور أحمد اليوم إذا كنت تعاني من أي من هذه الأعراض.</p><p></p>', '<h2><strong>Why Kidney Health Matters</strong></h2><p>The kidneys play a vital role in maintaining overall health by filtering waste products from the blood and regulating blood pressure. However, many people are unaware of kidney issues until they reach advanced stages.</p><h3><strong>Common Signs to Watch For</strong></h3><ul><li><p>Changes in urination frequency or color.</p></li><li><p>Swelling in the ankles, feet, or legs.</p></li><li><p>Persistent fatigue and weakness.</p></li><li><p>Shortness of breath without clear cause.</p></li><li><p>Early detection through regular check-ups is the best way to prevent chronic kidney disease. Consult Dr. Ahmed today if you experience any of these symptoms.</p></li></ul><p></p>', 'كليتاك هما الفلتر الصامت لجسمك. تعرف على أهمية الكشف المبكر وكيف يمكن لتغييرات بسيطة في نمط الحياة أن تحمي صحة كليتيك.', 'Your kidneys are the silent filters of your body. Learn why early detection is crucial and how simple lifestyle changes can protect your renal health.', ' صحة الكلى وطرق الوقاية | د. أحمد عبداللطيف', 'kidney health prevention', 'صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology.', 'صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology.', 'صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology.', NULL, 'published', 'https://dkqmympallxpdfypwxlr.supabase.co/storage/v1/object/public/media/images/92f08f82-32d0-4d4e-900b-4c11ae825fae.webp', '2026-05-09T00:01:52.527Z', '2026-05-16T15:29:41.255Z', false);
INSERT INTO "Service" ("id", "titleAr", "titleEn", "descriptionAr", "descriptionEn", "icon", "image", "order", "isActive", "createdAt", "updatedAt", "slug", "metaDescriptionAr", "metaDescriptionEn", "metaTitleAr", "metaTitleEn") VALUES ('cmp6qlkt00001vftkblsykdtq', 'علاج تضخم البروستاتا', 'Prostate Enlargement Treatment', 'علاج تضخم البروستاتا الحميد باستخدام أحدث التقنيات الجراحية وغير الجراحية.', 'Treatment of Benign Prostatic Hyperplasia (BPH) using the latest surgical and non-surgical techniques.', 'Shield', 'https://images.unsplash.com/photo-1579154235602-3c35bd79951e?q=80&w=800&auto=format&fit=crop', 1, true, '2026-05-15T09:50:42.325Z', '2026-05-15T09:50:42.325Z', 'prostate-enlargement-treatment', NULL, NULL, NULL, NULL);
