INSERT INTO "Service" ("id", "titleAr", "titleEn", "descriptionAr", "descriptionEn", "icon", "image", "order", "isActive", "createdAt", "updatedAt", "slug", "metaDescriptionAr", "metaDescriptionEn", "metaTitleAr", "metaTitleEn") VALUES ('cmp6qlkz90003vftklctbrfq1', 'تفتيت حصوات الجهاز البولي بالليزر', 'Laser Stone Fragmentation (HoLEP)', 'تفتيت حصوات الكلى، الحالب والمثانة باستخدام تقنية الهولميوم ليزر المتقدمة.', 'Fragmentation of kidney, ureter, and bladder stones using advanced Holmium laser technology.', 'Activity', 'https://images.unsplash.com/photo-1581595220892-b0739db3ba8c?q=80&w=800&auto=format&fit=crop', 3, true, '2026-05-15T09:50:42.549Z', '2026-05-15T09:50:42.549Z', 'laser-stone-fragmentation-holep', NULL, NULL, NULL, NULL);
