INSERT INTO "AuditLog" ("id", "userId", "action", "resource", "details", "ip", "createdAt") VALUES ('cmp8i576b0007l704a5woqd03', 'fe776d4a-928c-4cb6-ada8-f70e16a711b5', 'POST /api/media', 'media', '{"url":"https://dkqmympallxpdfypwxlr.supabase.co/storage/v1/object/public/media/images/92f08f82-32d0-4d4e-900b-4c11ae825fae.webp","type":"image","order":0,"titleAr":"669582872_950114700949053_4962132144196737033_n.jpg","titleEn":"669582872_950114700949053_4962132144196737033_n.jpg"}', '127.0.0.1', '2026-05-16T15:29:33.587Z');
INSERT INTO "AuditLog" ("id", "userId", "action", "resource", "details", "ip", "createdAt") VALUES ('cmp8i5dkn0009l704i3l7jw7m', 'fe776d4a-928c-4cb6-ada8-f70e16a711b5', 'PATCH /api/blog/cmoxkx85s0008vfj0bkybaeq7', 'blog', '{"slugAr":"طريقك-لصحة-الكلى-فهم-العلامات-المبكرة-وطرق-الوقاية","slugEn":"the-path-to-kidney-health-understanding-early-signs-and-prevention","status":"published","titleAr":"طريقك لصحة الكلى: فهم العلامات المبكرة وطرق الوقاية","titleEn":"The Path to Kidney Health: Understanding Early Signs and Prevention","keywords":"صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology.","contentAr":"<h2><strong>لماذا تعتبر صحة الكلى أمراً حيوياً؟</strong></h2><p>تلعب الكلى دوراً حيوياً في الحفاظ على الصحة العامة من خلال تصفية الفضلات من الدم وتنظيم ضغط الدم. ومع ذلك، لا يدرك الكثير من الناس وجود مشاكل في الكلى حتى تصل إلى مراحل متقدمة.</p><h3><strong>علامات شائعة يجب مراقبتها</strong></h3><ul><li><p>تغيرات في عدد مرات التبول أو لون البول.</p></li><li><p>تورم في الكاحلين أو القدمين أو الساقين.</p></li><li><p>التعب المستمر والضعف العام.</p></li><li><p>ضيق التنفس دون سبب واضح.</p></li></ul><p>الكشف المبكر من خلال الفحوصات الدورية هو أفضل وسيلة للوقاية من أمراض الكلى المزمنة. استشر الدكتور أحمد اليوم إذا كنت تعاني من أي من هذه الأعراض.</p><p></p>","contentEn":"<h2><strong>Why Kidney Health Matters</strong></h2><p>The kidneys play a vital role in maintaining overall health by filtering waste products from the blood and regulating blood pressure. However, many people are unaware of kidney issues until they reach advanced stages.</p><h3><strong>Common Signs to Watch For</strong></h3><ul><li><p>Changes in urination frequency or color.</p></li><li><p>Swelling in the ankles, feet, or legs.</p></li><li><p>Persistent fatigue and weakness.</p></li><li><p>Shortness of breath without clear cause.</p></li><li><p>Early detection through regular check-ups is the best way to prevent chronic kidney disease. Consult Dr. Ahmed today if you experience any of these symptoms.</p></li></ul><p></p>","excerptAr":"كليتاك هما الفلتر الصامت لجسمك. تعرف على أهمية الكشف المبكر وكيف يمكن لتغييرات بسيطة في نمط الحياة أن تحمي صحة كليتيك.","excerptEn":"Your kidneys are the silent filters of your body. Learn why early detection is crucial and how simple lifestyle changes can protect your renal health.","metaTitleAr":" صحة الكلى وطرق الوقاية | د. أحمد عبداللطيف","metaTitleEn":"kidney health prevention","featuredImage":"https://dkqmympallxpdfypwxlr.supabase.co/storage/v1/object/public/media/images/92f08f82-32d0-4d4e-900b-4c11ae825fae.webp","showOnHomepage":false,"metaDescriptionAr":"صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology.","metaDescriptionEn":"صحة الكلى، أمراض الكلى، الكشف المبكر، نصائح طبية، kidney health, urology."}', '127.0.0.1', '2026-05-16T15:29:41.879Z');
INSERT INTO "Technique" ("id", "titleAr", "titleEn", "descriptionAr", "descriptionEn", "image", "slug", "order", "isActive", "metaDescriptionAr", "metaDescriptionEn", "metaTitleAr", "metaTitleEn") VALUES ('cmp6qln0j000dvftk248chrpe', 'تبخير البروستاتا بالبلازما', 'Plasma Prostate Vaporization', 'تقنية آمنة لعلاج تضخم البروستاتا الحميد بدون جراحة تقليدية.', 'Safe technology for treating BPH without traditional surgery.', 'https://images.unsplash.com/photo-1579684385127-1ef15d508118?q=80&w=800&auto=format&fit=crop', 'plasma-vaporization', 1, true, NULL, NULL, NULL, NULL);
INSERT INTO "Technique" ("id", "titleAr", "titleEn", "descriptionAr", "descriptionEn", "image", "slug", "order", "isActive", "metaDescriptionAr", "metaDescriptionEn", "metaTitleAr", "metaTitleEn") VALUES ('cmp6qln0j000evftkngr6pvyv', 'ليزر هولميوم (HoLEP)', 'Holmium Laser (HoLEP)', 'استئصال البروستاتا بالليزر، الخيار الذهبي للأحجام الكبيرة.', 'Laser enucleation of the prostate, the gold standard for large prostates.', 'https://images.unsplash.com/photo-1581595220892-b0739db3ba8c?q=80&w=800&auto=format&fit=crop', 'holep', 2, true, NULL, NULL, NULL, NULL);
INSERT INTO "Technique" ("id", "titleAr", "titleEn", "descriptionAr", "descriptionEn", "image", "slug", "order", "isActive", "metaDescriptionAr", "metaDescriptionEn", "metaTitleAr", "metaTitleEn") VALUES ('cmp6qln0j000fvftkd09y9p0e', 'المناظير المرنة', 'Flexible Endoscopy', 'تفتيت حصوات الكلى والحالب بالليزر عبر المنظار المرن بدون جروح.', 'Laser fragmentation of kidney and ureteral stones via flexible endoscope.', 'https://images.unsplash.com/photo-1584017911766-d451b3d0e843?q=80&w=800&auto=format&fit=crop', 'flexible-endoscopy', 3, true, NULL, NULL, NULL, NULL);
